case object TokenRevoked extends TokenError
case object InvalidToken extends TokenError

object SecureTokenGenerator {

  // Use SecureRandom instead of scala.util.Random for cryptographic security
  private val secureRandom = new SecureRandom()

  private val alphanumericChars: Array[Char] =
    (('a' to 'z') ++ ('A' to 'Z') ++ ('0' to '9')).toArray

  /**
   * Generates a cryptographically secure random alphanumeric string.
   * Unlike scala.util.Random.alphanumeric which uses a non-cryptographic PRNG,
   * this uses java.security.SecureRandom.
   */
  def generateSecureToken(length: Int = 64): String = {
    require(length > 0, "Token length must be positive")
    val chars = new Array[Char](length)
    var i = 0
    while (i < length) {
      chars(i) = alphanumericChars(secureRandom.nextInt(alphanumericChars.length))
      i += 1
    }
    new String(chars)
  }

  /**
   * Generates a URL-safe Base64 encoded token from secure random bytes.
   */
  def generateSecureBase64Token(byteLength: Int = 48): String = {
    require(byteLength > 0, "Byte length must be positive")
    val bytes = new Array[Byte](byteLength)
    secureRandom.nextBytes(bytes)
    java.util.Base64.getUrlEncoder.withoutPadding().encodeToString(bytes)
  }
}

class TokenStore {
  private val sessionTokens: concurrent.Map[String, SessionToken] =
    new ConcurrentHashMap[String, SessionToken]().asScala

  private val apiKeys: concurrent.Map[String, ApiKey] =
    new ConcurrentHashMap[String, ApiKey]().asScala

  def getSessionCount: Int = sessionTokens.size
  def getApiKeyCount: Int = apiKeys.size

  def addSession(token: SessionToken): Unit =
    sessionTokens.put(token.token, token)

  def getSession(tokenValue: String): Option[SessionToken] =
    sessionTokens.get(tokenValue)

  def removeSession(tokenValue: String): Unit =
    sessionTokens.remove(tokenValue)

  def addApiKey(apiKey: ApiKey): Unit =
    apiKeys.put(apiKey.key, apiKey)

  def getApiKey(keyValue: String): Option[ApiKey] =
    apiKeys.get(keyValue)

  def removeApiKey(keyValue: String): Unit =
    apiKeys.remove(keyValue)

  def revokeSession(tokenValue: String): Boolean =
    sessionTokens.get(tokenValue) match {
      case Some(session) =>
        sessionTokens.put(tokenValue, session.copy(isRevoked = true))
        true
      case None => false
    }

  def revokeApiKey(keyValue: String): Boolean =
    apiKeys.get(keyValue) match {
      case Some(key) =>
        apiKeys.put(keyValue, key.copy(isRevoked = true))
        true
      case None => false
    }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = sessionTokens.filter { case (_, session) =>
      session.expiresAt.isBefore(now)
    }.keys.toList
    expired.foreach(sessionTokens.remove)
    expired.size
  }

  def cleanupExpiredApiKeys(): Int = {
    val now = Instant.now()
    val expired = apiKeys.filter { case (_, key) =>
      key.expiresAt.exists(_.isBefore(now))
    }.keys.toList
    expired.foreach(apiKeys.remove)
    expired.size
  }

  def getUserSessions(userId: String): List[SessionToken] =
    sessionTokens.values.filter(_.userId == userId).toList

  def revokeAllUserSessions(userId: String): Int = {
    val userSessions = sessionTokens.filter(_._2.userId == userId).keys.toList
    userSessions.foreach { tokenValue =>
      sessionTokens.get(tokenValue).foreach { session =>
        sessionTokens.put(tokenValue, session.copy(isRevoked = true))
      }
    }
    userSessions.size
  }
}

class SessionManagementService(
  sessionDuration: Duration = Duration.ofHours(24),
  maxSessionsPerUser: Int = 5,
  tokenLength: Int = 64
) {

  private val tokenStore = new TokenStore()

  /**
   * Creates a new session token for the given user.
   * Enforces maximum sessions per user by revoking the oldest if limit is exceeded.
   */
  def createSession(userId: String): Either[TokenError, SessionToken] = {
    require(userId != null && userId.trim.nonEmpty, "userId must not be null or empty")

    enforceMaxSessions(userId)

    val now = Instant.now()
    val token = SessionToken(
      token = SecureTokenGenerator.generateSecureToken(tokenLength),
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(sessionDuration)
    )
    tokenStore.addSession(token)
    Right(token)
  }

  /**
   * Validates a session token. Returns the session if valid.
   */
  def validateSession(tokenValue: String): Either[TokenError, SessionToken] = {
    if (tokenValue == null || tokenValue.trim.isEmpty) {
      return Left(InvalidToken)
    }

    tokenStore.getSession(tokenValue) match {
      case None => Left(TokenNotFound)
      case Some(session) if session.isRevoked => Left(TokenRevoked)
      case Some(session) if session.expiresAt.isBefore(Instant.now()) =>
        tokenStore.revokeSession(tokenValue)
        Left(TokenExpired)
      case Some(session) => Right(session)
    }
  }

  /**
   * Refreshes a session token, generating a new token value and extending expiry.
   * The old token is revoked.
   */
  def refreshSession(tokenValue: String): Either[TokenError, SessionToken] = {
    validateSession(tokenValue) match {
      case Left(error) => Left(error)
      case Right(oldSession) =>
        tokenStore.revokeSession(tokenValue)
        val now = Instant.now()
        val newToken = SessionToken(
          token = SecureTokenGenerator.generateSecureToken(tokenLength),
          userId = oldSession.userId,
          createdAt = now,
          expiresAt = now.plus(sessionDuration)
        )
        tokenStore.addSession(newToken)
        Right(newToken)
    }
  }

  /**
   * Revokes (invalidates) a session token.
   */
  def revokeSession(tokenValue: String): Boolean =
    tokenStore.revokeSession(tokenValue)

  /**
   * Revokes all sessions for a given user (e.g., on password change).
   */
  def revokeAllUserSessions(userId: String): Int =
    tokenStore.revokeAllUserSessions(userId)

  /**
   * Generates an API key pair (key + secret) for a user.
   */
  def generateApiKey(userId: String, expiresIn: Option[Duration] = None): ApiKey = {
    require(userId != null && userId.trim.nonEmpty, "userId must not be null or empty")

    val now = Instant.now()
    val apiKey = ApiKey(
      key = s"ak_${SecureTokenGenerator.generateSecureToken(32)}",
      secret = SecureTokenGenerator.generateSecureBase64Token(48),
      userId = userId,
      createdAt = now,
      expiresAt = expiresIn.map(now.plus)
    )
    tokenStore.addApiKey(apiKey)
    apiKey
  }

  /**
   * Validates an API key. Returns the ApiKey if valid.
   */
  def validateApiKey(keyValue: String): Either[TokenError, ApiKey] = {
    if (keyValue == null || keyValue.trim.isEmpty) {
      return Left(InvalidToken)
    }

    tokenStore.getApiKey(keyValue) match {
      case None => Left(TokenNotFound)
      case Some(apiKey) if apiKey.isRevoked => Left(TokenRevoked)
      case Some(apiKey) if apiKey.expiresAt.exists(_.isBefore(Instant.now())) =>
        tokenStore.revokeApiKey(keyValue)
        Left(TokenExpired)
      case Some(apiKey) => Right(apiKey)
    }
  }

  /**
   * Revokes an API key.
   */
  def revokeApiKey(keyValue: String): Boolean =
    tokenStore.revokeApiKey(keyValue)

  /**
   * Performs cleanup of expired tokens. Should be called periodically.
   */
  def cleanup(): (Int, Int) = {
    val sessions = tokenStore.cleanupExpiredSessions()
    val keys = tokenStore.cleanupExpiredApiKeys()
    (sessions, keys)
  }

  /**
   * Constant-time string comparison to prevent timing attacks.
   */
  def constantTimeEquals(a: String, b: String): Boolean = {
    if (a == null || b == null) return false
    val aBytes = a.getBytes("UTF-8")
    val bBytes = b.getBytes("UTF-8")
    java.security.MessageDigest.isEqual(aBytes, bBytes)
  }

  /**
   * Validates an API key and secret pair using constant-time comparison.
   */
  def validateApiKeyWithSecret(keyValue: String, secretValue: String): Either[TokenError, ApiKey] = {
    validateApiKey(keyValue) match {
      case Left(error) => Left(error)
      case Right(apiKey) =>
        if (constantTimeEquals(apiKey.secret, secretValue)) Right(apiKey)
        else Left(InvalidToken)
    }
  }

  private def enforceMaxSessions(userId: String): Unit = {
    val userSessions = tokenStore.getUserSessions(userId)
      .filterNot(_.isRevoked)
      .sortBy(_.createdAt)

    if (userSessions.size >= maxSessionsPerUser) {
      val sessionsToRevoke = userSessions.take(userSessions.size - maxSessionsPerUser + 1)
      sessionsToRevoke.foreach(s => tokenStore.revokeSession(s.token))
    }
  }

  def getActiveSessionCount: Int = tokenStore.getSessionCount
  def getActiveApiKeyCount: Int = tokenStore.getApiKeyCount
}

